def validPath(n, edges, source, destination):
    if source == destination:
        return True
    adj = defaultdict(list)
    for u, v in edges:
        adj[u].append(v)
        adj[v].append(u)

    visited = {source}
    queue = deque([source])
    while queue:
        curr = queue.popleft()
        if curr == destination:
            return True
        for neighbor in adj[curr]:
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append(neighbor)
    return False

