def numIslands(grid):
    if not grid:
        return 0
    r, c = len(grid), len(grid[0])
    islands = 0

    def dfs(i, j):
        if i < 0 or i >= r or j < 0 or j >= c or grid[i][j] == '0':
            return
        # Sink the land
        grid[i][j] = '0'
        # Visit neighbors
        dfs(i + 1, j)
        dfs(i - 1, j)
        dfs(i, j + 1)
        dfs(i, j - 1)

    for i in range(r):
        for j in range(c):
            if grid[i][j] == '1':
                islands += 1
                dfs(i, j)
    return islands

