int numIslands(vector<vector<char>>& grid) {
    if (grid.empty()) return 0;
    int r = grid.size();
    int c = grid[0].size();
    int islands = 0;

    auto dfs = [&](auto& self, int i, int j) -> void {
        if (i < 0 || i >= r || j < 0 || j >= c || grid[i][j] == '0') return;
        grid[i][j] = '0'; // Sink current land
        self(self, i + 1, j);
        self(self, i - 1, j);
        self(self, i, j + 1);
        self(self, i, j - 1);
    };

    for (int i = 0; i < r; ++i) {
        for (int j = 0; j < c; ++j) {
            if (grid[i][j] == '1') {
                islands++;
                dfs(dfs, i, j);
            }
        }
    }
    return islands;
}

