class Node:
    def __init__(self, val = 0, neighbors = None):
        self.val = val
        self.neighbors = neighbors if neighbors is not None else []

def cloneGraph(node):
    if not node:
        return None
    cloned = {}

    def dfs(curr):
        if curr in cloned:
            return cloned[curr]
        # Create copy
        copy = Node(curr.val)
        cloned[curr] = copy
        # Map neighbors
        for neighbor in curr.neighbors:
            copy.neighbors.append(dfs(neighbor))
        return copy

    return dfs(node)

