def alienOrder(words):
    adj = {char: set() for word in words for char in word}

    # Build edges
    for i in range(len(words) - 1):
        w1, w2 = words[i], words[i+1]
        min_len = min(len(w1), len(w2))
        if len(w1) > len(w2) and w1[:min_len] == w2[:min_len]:
            return "" # Mismatch: prefix word must be shorter
        for j in range(min_len):
            if w1[j] != w2[j]:
                adj[w1[j]].add(w2[j])
                break

    state = {} # char -> False (visiting), True (visited)
    res = []

    def dfs(char):
        if char in state:
            return state[char]
        state[char] = False # Visiting
        for neighbor in adj[char]:
            if not dfs(neighbor):
                return False
        state[char] = True # Visited
        res.append(char)
        return True

    for char in adj:
        if not dfs(char):
            return ""

    res.reverse()
    return "".join(res)

