string alienOrder(vector<string>& words) {
    unordered_map<char, unordered_set<char>> adj;
    for (const string& word : words) {
        for (char c : word) adj[c] = unordered_set<char>();
    }

    for (size_t i = 0; i < words.size() - 1; ++i) {
        string w1 = words[i], w2 = words[i + 1];
        size_t min_len = min(w1.size(), w2.size());
        if (w1.size() > w2.size() && w1.substr(0, min_len) == w2.substr(0, min_len)) {
            return ""; // Prefix constraint violation
        }
        for (size_t j = 0; j < min_len; ++j) {
            if (w1[j] != w2[j]) {
                adj[w1[j]].insert(w2[j]);
                break;
            }
        }
    }

    unordered_map<char, bool> state; // false = visiting, true = visited
    string res = "";

    auto dfs = [&](auto& self, char c) -> bool {
        if (state.count(c)) return state[c];
        state[c] = false; // Visiting
        for (char neighbor : adj[c]) {
            if (!self(self, neighbor)) return false;
        }
        state[c] = true; // Visited
        res += c;
        return true;
    };

    for (auto& [c, neighbors] : adj) {
        if (!dfs(dfs, c)) return "";
    }

    reverse(res.begin(), res.end());
    return res;
}

