def criticalConnections(n, connections):
    # Build adjacency list
    adj = {i: [] for i in range(n)}
    for u, v in connections:
        adj[u].append(v)
        adj[v].append(u)

    discovery = [-1] * n
    low = [-1] * n
    bridges = []
    time = 0

    def dfs(curr, parent):
        nonlocal time
        discovery[curr] = low[curr] = time
        time += 1

        for neighbor in adj[curr]:
            if neighbor == parent:
                continue
            if discovery[neighbor] == -1:
                # Recurse
                dfs(neighbor, curr)
                low[curr] = min(low[curr], low[neighbor])
                # Bridge check condition
                if low[neighbor] > discovery[curr]:
                    bridges.append([curr, neighbor])
            else:
                # Back-edge update
                low[curr] = min(low[curr], discovery[neighbor])

    dfs(0, -1)
    return bridges

