vector<vector<int>> criticalConnections(int n, vector<vector<int>>& connections) {
    vector<vector<int>> adj(n);
    for (auto& conn : connections) {
        adj[conn[0]].push_back(conn[1]);
        adj[conn[1]].push_back(conn[0]);
    }
    vector<int> discovery(n, -1);
    vector<int> low(n, -1);
    vector<vector<int>> bridges;
    int time = 0;

    auto dfs = [&](auto& self, int curr, int parent) -> void {
        discovery[curr] = low[curr] = time++;
        for (int neighbor : adj[curr]) {
            if (neighbor == parent) continue;
            if (discovery[neighbor] == -1) {
                self(self, neighbor, curr);
                low[curr] = min(low[curr], low[neighbor]);
                if (low[neighbor] > discovery[curr]) {
                    bridges.push_back({curr, neighbor});
                }
            } else {
                low[curr] = min(low[curr], discovery[neighbor]);
            }
        }
    };

    dfs(dfs, 0, -1);
    return bridges;
}
